import React, { Component } from "react";
import icon from "./logo16.png";
import "./style.scss";

export default class extends Component {
  constructor(props, context) {
    super(props, context);
    this.state = { NODE_ENV: false };

    // console.log(
    //   `constructor ${Object.getOwnPropertyNames(window).sort().length}`
    // );
  }

  componentDidMount() {
    // console.log("componentDidMount: ", this);
    require("./script.js");
    // console.log("process.env: ", process.env);
    if (!process.env.NODE_ENV || process.env.NODE_ENV === "development") {
      // dev code
      this.setState({
        NODE_ENV: process.env.NODE_ENV
      });
    } else {
      // production code
    }
  }

  render() {
    // const { title, icon } = "";
    const { title } = "";
    if (this.state.NODE_ENV) {
      return false;
    }
    return (
      <>
        <div className="add-to-home-banner">
          <div className="add-to-home-content">
            {icon ? <img className="add-to-home-icon" src={icon} /> : null}
            <div className="add-to-home-text">
              <a id="butInstall">
                {title || "Adicionar o aplicativo a tela inicial"}
              </a>
            </div>
          </div>
          <span className="add-to-home-close-btn">x</span>
        </div>
      </>
    );
  }
}
